const json=$input.first().json;
const raw=(json.chatInput||json.input||json.message||json.text||json.userMessage||'').trim();
const msg=raw.replace(/^\[\s*/,'').replace(/\s*\]$/,'').trim();
if(msg.toLowerCase()==='list')return[{json:{mode:'list'}}];
const rem=msg.match(/^remove\s+([A-Z0-9]{6,8})$/i);
if(rem)return[{json:{mode:'remove',companyNumber:rem[1].toUpperCase()}}];
const upd=msg.match(/^update\s+([A-Z0-9]{6,8})\s+(.+)$/i);
if(upd){
  const companyNumber=upd[1].toUpperCase();
  const fieldsRaw=upd[2].split('|').map(function(s){return s.trim();}).filter(Boolean);
  const updates=[];
  const fieldErrors=[];
  for(let i=0;i<fieldsRaw.length;i++){
    const fm=fieldsRaw[i].match(/^([^=]+?)\s*=\s*(.+)$/);
    if(!fm){fieldErrors.push('Cannot parse field "'+fieldsRaw[i]+'"');continue;}
    updates.push({field:fm[1].trim(),value:fm[2].trim()});
  }
  if(updates.length===0){
    throw new Error((fieldErrors.length?fieldErrors.join('; '):'No valid field updates found.')+' Format: update <RegNo> <Field>=<Value> | <Field>=<Value>');
  }
  return[{json:{mode:'update',companyNumber:companyNumber,updates:updates}}];
}
const lines=msg.split(/\r?\n/).map(function(l){return l.trim();}).filter(Boolean);
const results=[];
const errors=[];
for(let i=0;i<lines.length;i++){
  const line=lines[i];
  const parts=line.match(/^add\s+([A-Z0-9]{6,8})\s+(\d{1,2})\s+(.+)$/i);
  if(!parts){errors.push('Line '+(i+1)+': cannot parse "'+line+'"');continue;}
  const pipeParts=parts[3].split('|');
  const products=pipeParts[0].split(',').map(function(p){return p.trim();}).filter(Boolean);
  const note=pipeParts.length>1?pipeParts.slice(1).join('|').trim():'';
  results.push({json:{mode:'add',companyNumber:parts[1].toUpperCase(),ranking:Number(parts[2]),products:products,note:note}});
}
if(results.length===0){
  const hint=errors.length>0?errors.join('; '):'No valid commands found.';
  throw new Error(hint+' Format: add <RegNo> <Ranking> <Products> | <Note>');
}
return results;

const resp=$input.first().json;
