return[{json:{s3Url:s3Url}}];

try {
  const raw = $input.first().json.data;
  if (!raw) return [{json:{ollamaBody:null,hasImages:false,debug:'no data from download'}}];
  const content = String(raw).substring(0, 500000);

  // 1. Build context map from xbrli:context blocks
  const ctxMap = {};
  const ctxRe = /<xbrli:context\s+id="([^"]+)"([\s\S]*?)<\/xbrli:context>/gi;
  let cm;
  while ((cm = ctxRe.exec(content)) !== null) {
    const id = cm[1];
    const body = cm[2];
    const em = body.match(/<xbrli:endDate>\s*([^<]+?)\s*<\/xbrli:endDate>/i);
    const im = body.match(/<xbrli:instant>\s*([^<]+?)\s*<\/xbrli:instant>/i);
    ctxMap[id] = {end:em?em[1].trim():null, instant:im?im[1].trim():null, hasSegment:/<xbrli:segment/i.test(body)};
  }

  // Latest year-end date across all contexts
  let latestEnd = null;
  for (const c of Object.values(ctxMap)) {
    const d = c.end || c.instant;
    if (d && (!latestEnd || d > latestEnd)) latestEnd = d;
  }

  // Parent-preferred context IDs: no segment dimension, latest end date
  const periodCtxIds = Object.entries(ctxMap).filter(function([,c]){return c.end===latestEnd&&!c.hasSegment;}).map(function([id]){return id;});
  const instantCtxIds = Object.entries(ctxMap).filter(function([,c]){return c.instant===latestEnd&&!c.hasSegment;}).map(function([id]){return id;});

  // 2. Parse all ix:nonFraction and ix:nonNumeric elements (handles any attribute order)
  const elements = [];
  const reOpen = /<ix:(nonFraction|nonNumeric)\b([^>]*)>/gi;
  let om;
  while ((om = reOpen.exec(content)) !== null) {
    const tagType = om[1];
    const attrs = om[2];
    const nameM  = attrs.match(/\bname="([^"]+)"/i);
    const ctxM   = attrs.match(/\bcontextRef="([^"]+)"/i);
    const signM  = attrs.match(/\bsign="([^"]+)"/i);
    const scaleM = attrs.match(/\bscale="(-?[0-9]+)"/i);
    if (!nameM || !ctxM) continue;
    const closeTag = '</ix:' + tagType + '>';
    const start = om.index + om[0].length;
    const end = content.indexOf(closeTag, start);
    if (end === -1) continue;
    const inner = content.substring(start, end).replace(/<[^>]+>/g,'').replace(/\s+/g,' ').trim();
    elements.push({name:nameM[1], ctx:ctxM[1], sign:signM?signM[1]:null, scale:scaleM?parseInt(scaleM[1]):0, text:inner});
  }

  // 3. Helper functions
  function parseNum(el) {
    if (!el || !el.text) return null;
    const t = el.text.trim();
    const isNeg = el.sign === '-' || /^\(.*\)$/.test(t);
    const clean = t.replace(/[£$€,\s()]/g, '');
    const n = parseFloat(clean);
    if (isNaN(n)) return null;
    return (isNeg ? -n : n) * Math.pow(10, el.scale || 0);
  }
  function findVal(ctxIds, concepts) {
    for (const name of concepts) {
      const el = elements.find(function(e){return e.name===name&&ctxIds.includes(e.ctx);});
      if (el) {const v = parseNum(el); if (v !== null) return v;}
    }
    return null;
  }

  // 4. Extract key financial values directly from XBRL tags
  const yearEndEl = elements.find(function(e){return e.name==='bus:EndDateForPeriodCoveredByReport';});
  const yearEndRaw = yearEndEl ? yearEndEl.text.trim() : latestEnd;
  const yearEnd = yearEndRaw ? ((yearEndRaw.match(/\d{4}/)||[])[0]||yearEndRaw) : null;

  const xbrl = {
    turnover:      findVal(periodCtxIds,  ['core:TurnoverRevenue','core:Turnover','bus:Turnover','core:Revenue']),
    employees:     findVal(periodCtxIds,  ['core:AverageNumberEmployeesDuringPeriod','bus:AverageNumberEmployeesDuringPeriod','core:EmployeesNumber']),
    netAssets:     findVal(instantCtxIds, ['core:NetAssetsLiabilities','core:Equity','core:TotalEquity','bus:NetAssetsLiabilities']),
    profitAfterTax:findVal(periodCtxIds,  ['core:ProfitLoss','core:ProfitLossForPeriod','core:ProfitLossAttributableToOwnersOfParent']),
    yearEnd
  };

  // 5. If all numeric fields found, skip Ollama entirely
  const foundFields   = Object.entries(xbrl).filter(function([,v]){return v!==null;});
  const missingFields = Object.entries(xbrl).filter(function([k,v]){return v===null&&k!=='yearEnd';});
  if (missingFields.length === 0) {
    return [{json:{ollamaBody:null, hasImages:false, xbrlExtracted:xbrl}}];
  }

  // 6. Fallback: full-document Ollama analysis for any missing fields
  const cleanText = content
    .replace(/<[^>]{0,500}>/g,' ')
    .replace(/&nbsp;/g,' ')
    .replace(/&amp;/g,'&')
    .replace(/&pound;/gi,'£')
    .replace(/&#[0-9]+;/g,' ')
    .replace(/[ \t]{2,}/g,' ')
    .replace(/\n{3,}/g,'\n\n');

  const fmt = function(v){return v==null?'null':(v<0?'-£'+Math.abs(Math.round(v)).toLocaleString():'£'+Math.round(v).toLocaleString());};
  const preContext = foundFields.length > 0
    ? 'The following were already extracted from XBRL tags (high confidence — use these unless the document clearly contradicts them):\n'
      + foundFields.map(function([k,v]){
          if (k==='yearEnd') return 'Year: '+v;
          if (k==='employees') return 'Employees: '+v;
          if (k==='turnover') return 'Turnover: '+fmt(v);
          if (k==='netAssets') return 'Net assets: '+fmt(v);
          if (k==='profitAfterTax') return 'Profit: '+fmt(v);
          return k+': '+v;
        }).join('\n') + '\n\n'
    : '';

  const prompt = 'You are reading UK company accounts from an iXBRL filing. Find these five figures for the CURRENT YEAR from the PARENT COMPANY (not group/consolidated if both are shown).\n\n'
    + preContext
    + 'Find or confirm:\n1. Annual turnover or revenue (GBP)\n2. Average number of employees\n3. Net assets or total equity (GBP)\n4. Profit after tax (GBP) — negative if a loss\n5. Financial year end date\n\n'
    + 'In UK accounts, figures in parentheses e.g. (45,000) are negative. Always output negatives with a minus sign.\n\n'
    + 'Respond with ONLY these five lines:\nTurnover: £2,450,000\nEmployees: 45\nNet assets: £890,000\nProfit: £123,456\nYear: 2023\n\n'
    + 'If a loss: Profit: -£45,000\nIf not found: write null.\n\nACCOUNTS TEXT:\n' + cleanText;

  const body = JSON.stringify({model:'qwen3.5:27b', prompt, stream:false, think:false});
  return [{json:{ollamaBody:body, hasImages:false, xbrlExtracted:xbrl}}];
} catch(e) {
  return [{json:{ollamaBody:null, hasImages:false, debug:'error: '+String(e)}}];
}

const companyNumber=$('CH: Company').first().json.company_number;
const parseItems=$('Parse Input').all();
const matched=parseItems.find(function(item){return item.json.companyNumber&&item.json.companyNumber.toUpperCase()===companyNumber.toUpperCase();});
const input=matched?matched.json:{companyNumber:companyNumber,ranking:5,products:[],note:''};
const company=$('CH: Company').first().json;
const officers=$('CH: Officers').first().json;
const webData=$input.first().json;
let financials={turnover:null,employees:null,netAssets:null,profitAfterTax:null,accountsYear:null};
try {
  let xbrlDirect = null;
  try {
    const xbrlNode = $('Extract iXBRL Text').first();
    if (xbrlNode && xbrlNode.json && xbrlNode.json.xbrlExtracted && xbrlNode.json.ollamaBody === null) {
      xbrlDirect = xbrlNode.json.xbrlExtracted;
    }
  } catch(xe) {}

  if (xbrlDirect) {
    financials = {
      turnover:      xbrlDirect.turnover,
      employees:     xbrlDirect.employees,
      netAssets:     xbrlDirect.netAssets,
      profitAfterTax:xbrlDirect.profitAfterTax,
      accountsYear:  xbrlDirect.yearEnd
    };
  } else {
    const finRaw = $('HTTP: Extract Financials').first().json;
    if (finRaw && finRaw.response) {
      const text = finRaw.response;
      try {
        const parsed = JSON.parse(text);
        financials = {
          turnover:      parsed.turnover||null,
          employees:     parsed.employees||null,
          netAssets:     parsed.netAssets||null,
          profitAfterTax:parsed.profitAfterTax||parsed.profit||null,
          accountsYear:  parsed.year||null
        };
      } catch(e) {
        const lines = text.split(/\r?\n/);
        const getNum = function(key){
          const line = lines.find(function(l){return l.toLowerCase().startsWith(key.toLowerCase());});
          if (!line) return null;
          const neg = line.includes('-') || line.includes('(');
          const n = parseInt(line.slice(key.length).replace(/[^0-9]/g,''));
          return isNaN(n) ? null : (neg ? -n : n);
        };
        const yearLine = lines.find(function(l){return l.toLowerCase().startsWith('year:');});
        const yM = yearLine ? yearLine.match(/(20\d\d|19\d\d)/) : null;
        financials = {
          turnover:      getNum('Turnover:'),
          employees:     getNum('Employees:'),
          netAssets:     getNum('Net assets:'),
          profitAfterTax:getNum('Profit:'),
          accountsYear:  yM?yM[1]:null
        };
      }
    }
  }
} catch(e) {}
