const rows=list.map(function(p){const fin=p.financials||{};const bd='border-bottom:'+(p.rankingNote?'none':'1px solid #ddd');const noteRow=p.rankingNote?'<tr><td colspan="9" style="padding:4px 8px 10px;color:#666;font-style:italic;font-size:12px;border-bottom:1px solid #ddd"><em>Note: '+p.rankingNote+'</em></td></tr>':'';return '<tr>'+'<td style="padding:8px;'+bd+'"><strong><a href="'+ch(p.companyNumber)+'" target="_blank">'+p.companyName+'</a></strong><br><small>'+p.companyNumber+'</small></td>'+'<td style="padding:8px;'+bd+';text-align:center"><strong>'+p.customerRanking+'/10</strong></td>'+'<td style="padding:8px;'+bd+'">'+(p.region||'—')+'</td>'+'<td style="padding:8px;'+bd+'">'+(p.products||[]).join(', ')+'</td>'+'<td style="padding:8px;'+bd+'">'+(p.sicCodes||[]).join(', ')+'</td>'+'<td style="padding:8px;'+bd+'">'+(fin.turnover!=null?'£'+Math.round(fin.turnover).toLocaleString():'—')+'</td>'+'<td style="padding:8px;'+bd+';text-align:center">'+(fin.employees!=null?fin.employees:'—')+'</td>'+'<td style="padding:8px;'+bd+';text-align:center">'+confBadge(p.accountsConfidence)+'</td>'+'<td style="padding:8px;'+bd+'">'+(p.profileDate||'')+'</td>'+'</tr>'+noteRow;}).join('');
const avgRanking=list.length?(list.reduce(function(s,p){return s+p.customerRanking;},0)/list.length).toFixed(1):'0';
const html='<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:1200px;margin:0 auto">'+'<h2 style="color:#2c3e50">Portland Fuel Customer Profiles</h2>'+'<p><b>'+list.length+' companies</b> | Average ranking: '+avgRanking+'/10 | '+date+(list.length===0?' — No profiles saved yet.':'')+'</p>'+'<table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse">'+'<thead><tr style="background:#2c3e50;color:#fff">'+'<th style="padding:8px;text-align:left">Company</th>'+'<th style="padding:8px;width:60px">Rank</th>'+'<th style="padding:8px;width:110px">Region</th>'+'<th style="padding:8px;width:160px">Products</th>'+'<th style="padding:8px;width:80px">SIC</th>'+'<th style="padding:8px;width:100px">Turnover</th>'+'<th style="padding:8px;width:80px">Employees</th>'+'<th style="padding:8px;width:80px">Confidence</th>'+'<th style="padding:8px;width:90px">Profiled</th>'+'</tr></thead><tbody>'+rows+'</tbody></table>'+'<p style="color:#999;font-size:11px">Generated '+new Date().toISOString()+' via n8n / amelai</p>'+'</body></html>';
const esc=function(v){return '"'+(String(v||'')).replace(/"/g,'""')+'"';};
const csvHeader='Company Number,Company Name,Region,Ranking,Products,SIC Codes,Turnover,Employees,Net Assets,Accounts Year,Confidence,Ranking Note,Profile Date';
const csvRows=list.map(function(p){const fin=p.financials||{};return [esc(p.companyNumber),esc(p.companyName),esc(p.region||''),p.customerRanking,esc((p.products||[]).join('; ')),esc((p.sicCodes||[]).join('; ')),fin.turnover!=null?Math.round(fin.turnover):'',fin.employees!=null?fin.employees:'',fin.netAssets!=null?Math.round(fin.netAssets):'',esc(fin.accountsYear||''),esc(p.accountsConfidence||''),esc(p.rankingNote||''),esc(p.profileDate||'')].join(',');});
const csvContent=csvHeader+'\n'+csvRows.join('\n');
const csvBase64=Buffer.from(csvContent,'utf-8').toString('base64');
return[{json:{subject:subj,htmlBody:html,csvBase64:csvBase64}}];

const input=$('Parse Input').first().json;
const store=$getWorkflowStaticData('global');
if(!store.profiles)store.profiles={};
const existing=store.profiles[input.companyNumber];
if(!existing)return[{json:{companyNumber:input.companyNumber,companyName:'Unknown',removed:false}}];
const name=existing.companyName||input.companyNumber;
delete store.profiles[input.companyNumber];
return[{json:{companyNumber:input.companyNumber,companyName:name,removed:true}}];

const p=$input.first().json;
const date=new Date().toLocaleDateString('en-GB');
const subj=p.removed?'Profile Removed: '+p.companyName+' ('+p.companyNumber+')':'Profile Not Found: '+p.companyNumber;
const msg=p.removed?'<p>The profile for <strong>'+p.companyName+'</strong> ('+p.companyNumber+') has been removed from the customer database.</p>':'<p>No profile was found for company number <strong>'+p.companyNumber+'</strong>. Nothing was deleted.</p>';
const html='<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto"><h2 style="color:#2c3e50">'+(p.removed?'Profile Removed':'Profile Not Found')+'</h2>'+msg+'<p style="color:#999;font-size:11px">'+date+' via n8n / amelai</p></body></html>';
return[{json:{subject:subj,htmlBody:html}}];

const input=$('Parse Input').first().json;
const store=$getWorkflowStaticData('global');
if(!store.profiles)store.profiles={};
const existing=store.profiles[input.companyNumber];
if(!existing){
  return[{json:{companyNumber:input.companyNumber,companyName:'Unknown',updated:false,changes:[],errors:['No profile found for '+input.companyNumber+'. Use "add" to create one first.']}}];
}
if(!existing.financials)existing.financials={};

const fieldMap={
  'company name':{obj:'root',prop:'companyName',type:'string'},
  'region':{obj:'root',prop:'region',type:'string'},
  'ranking':{obj:'root',prop:'customerRanking',type:'number'},
  'products':{obj:'root',prop:'products',type:'array-merge'},
  'sic codes':{obj:'root',prop:'sicCodes',type:'array-merge'},
  'turnover':{obj:'financials',prop:'turnover',type:'number'},
  'employees':{obj:'financials',prop:'employees',type:'number'},
  'net assets':{obj:'financials',prop:'netAssets',type:'number'},
  'accounts year':{obj:'financials',prop:'accountsYear',type:'string'},
  'confidence':{obj:'root',prop:'accountsConfidence',type:'string'},
  'ranking note':{obj:'root',prop:'rankingNote',type:'string'},
  'profile date':{obj:'root',prop:'profileDate',type:'string'}
};

const changes=[];
const errors=[];

(input.updates||[]).forEach(function(upd){
  const def=fieldMap[upd.field.trim().toLowerCase()];
  if(!def){errors.push('Unknown field "'+upd.field+'" — must match a CSV column (e.g. Ranking, Products, Region, Ranking Note).');return;}
  const target=def.obj==='financials'?existing.financials:existing;

  if(def.type==='number'){
    const num=Number(upd.value);
    if(isNaN(num)){errors.push('"'+upd.field+'" must be a number, got "'+upd.value+'"');return;}
    const before=target[def.prop];
    target[def.prop]=num;
    changes.push(upd.field+': '+(before==null?'—':before)+' → '+num);
  } else if(def.type==='array-merge'){
    const additions=upd.value.split(',').map(function(v){return v.trim();}).filter(Boolean);
    const current=target[def.prop]||[];
    const before=current.slice();
    const merged=current.slice();
    additions.forEach(function(a){
      if(!merged.some(function(m){return m.toLowerCase()===a.toLowerCase();})){merged.push(a);}
    });
    target[def.prop]=merged;
    changes.push(upd.field+': '+(before.join(', ')||'—')+' → '+merged.join(', '));
  } else {
    const before=target[def.prop];
    target[def.prop]=upd.value;
    changes.push(upd.field+': '+(before||'—')+' → '+upd.value);
  }
});

store.profiles[input.companyNumber]=existing;
return[{json:{companyNumber:existing.companyNumber,companyName:existing.companyName,updated:changes.length>0,changes:changes,errors:errors}}];

