  msg='<p>No profile was found for company number <strong>'+p.companyNumber+'</strong>. Use <code>add</code> to create it first.</p>';
} else {
  msg='<p>Profile for <strong>'+p.companyName+'</strong> ('+p.companyNumber+') updated.</p>'+(changesList?'<ul>'+changesList+'</ul>':'<p>No fields were changed.</p>')+(errorsList?'<p><strong>Issues:</strong></p><ul>'+errorsList+'</ul>':'');
}
const html='<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto"><h2 style="color:#2c3e50">'+(notFound?'Profile Not Found':(p.updated?'Profile Updated':'Update Issue'))+'</h2>'+msg+'<p style="color:#999;font-size:11px">'+date+' via n8n / amelai</p></body></html>';
return[{json:{subject:subj,htmlBody:html}}];
